1	/**
2	 * Check a single field's value against a declared type. Returns an error
3	 * string describing the problem, or `undefined` when the value is fine.
4	 */
5	function checkField(field: string, type: string, obj: Record<string, unknown>): string | undefined {
6	  // A trailing `?` marks the field optional: absent (or explicitly `undefined`)
7	  // is fine; a present non-undefined value is checked against the base type.
8	  const optional = type.endsWith('?');
9	  const base = optional ? type.slice(0, -1) : type;
10	  if (!(field in obj) || obj[field] === undefined) {
11	    return optional ? undefined : `missing required field "${field}" (expected ${type})`;
12	  }
13	
14	  const fieldValue = obj[field];
15	
16	  switch (base) {
17	    case 'string':
18	      if (typeof fieldValue !== 'string') return `field "${field}" must be a string (got ${describe(fieldValue)})`;
19	      break;
20	    case 'number':
21	      if (typeof fieldValue !== 'number') return `field "${field}" must be a number (got ${describe(fieldValue)})`;
22	      break;
23	    case 'boolean':
24	      if (typeof fieldValue !== 'boolean') return `field "${field}" must be a boolean (got ${describe(fieldValue)})`;
25	      break;
26	    case 'object':
27	      if (typeof fieldValue !== 'object' || fieldValue === null || Array.isArray(fieldValue))
28	        return `field "${field}" must be an object (got ${describe(fieldValue)})`;
29	      break;
30	    case 'array':
31	      if (!Array.isArray(fieldValue)) return `field "${field}" must be an array (got ${describe(fieldValue)})`;
32	      break;
33	    case 'any':
34	      // Accept any non-undefined value
35	      if (fieldValue === undefined) return `field "${field}" is required (got undefined)`;
36	      break;
37	    default:
38	      // Unknown type — be lenient
39	      break;
40	  }
41	  return undefined;
42	}
43	
44	function describe(value: unknown): string {
45	  if (value === undefined) return 'undefined';
46	  if (value === null) return 'null';
47	  if (Array.isArray(value)) return 'array';
48	  return typeof value;
49	}
50	
51	/**
52	 * Validate `seed` against a tasklist's declared `input` schema (from
53	 * tasklists/<name>/index.md frontmatter). Returns a list of human-readable
54	 * error strings naming the missing/mistyped fields; empty when valid.
55	 * Schema: { field: "string"|"number"|"boolean"|"object"|"array"|"any" }
56	 */
57	export function validateInput(input: Record<string, string>, value: unknown): string[] {
58	  if (typeof value !== 'object' || value === null || Array.isArray(value)) {
59	    return [`expected an object with fields: ${Object.keys(input).join(', ')} (got ${describe(value)})`];
60	  }
61	
62	  const obj = value as Record<string, unknown>;
63	  const errors: string[] = [];
64	  for (const [field, type] of Object.entries(input)) {
65	    const err = checkField(field, type, obj);
66	    if (err) errors.push(err);
67	  }
68	  return errors;
69	}
70	
71	/**
72	 * Validate that value matches the output schema.
73	 * Schema: { field: "string"|"number"|"boolean"|"object"|"array" }
74	 */
75	export function validateOutput(output: Record<string, string>, value: unknown): boolean {
76	  if (typeof value !== 'object' || value === null || Array.isArray(value)) {
77	    return false;
78	  }
79	
80	  const obj = value as Record<string, unknown>;
81	
82	  for (const [field, type] of Object.entries(output)) {
83	    // A trailing `?` marks the field optional (absent / `undefined` is allowed).
84	    const optional = type.endsWith('?');
85	    const base = optional ? type.slice(0, -1) : type;
86	    if (!(field in obj) || obj[field] === undefined) {
87	      if (optional) continue;
88	      return false;
89	    }
90	
91	    const fieldValue = obj[field];
92	
93	    switch (base) {
94	      case 'string':
95	        if (typeof fieldValue !== 'string') return false;
96	        break;
97	      case 'number':
98	        if (typeof fieldValue !== 'number') return false;
99	        break;
100	      case 'boolean':
101	        if (typeof fieldValue !== 'boolean') return false;
102	        break;
103	      case 'object':
104	        if (typeof fieldValue !== 'object' || fieldValue === null || Array.isArray(fieldValue))
105	          return false;
106	        break;
107	      case 'array':
108	        if (!Array.isArray(fieldValue)) return false;
109	        break;
110	      case 'any':
111	        // Accept any non-undefined value
112	        if (fieldValue === undefined) return false;
113	        break;
114	      default:
115	        // Unknown type — be lenient
116	        break;
117	    }
118	  }
119	
120	  return true;
121	}
