2	import type { ForkEngine } from '../fork/fork.js';
3	import { loadTasklist } from '../spaces/tasklist-load.js';
4	import { validateDag, findReadyTasks, resolveGoalTask } from './dag.js';
5	import type { TaskNode } from '../spaces/tasklist-load.js';
6	import type { Tracer, TraceScope } from '../sandbox/trace.js';
7	import { validateInput } from './schema.js';
8	import type { TaskEnvelope, DegradeReason } from '../exec/envelope.js';
9	
10	/** Resolve a `forEach` reference ("taskId" or "taskId.field.subfield") against accumulated
11	 *  task outputs. Returns the referenced array, or [] when missing / not an array. */
12	function resolveForEachItems(ref: string, allOutputs: Record<string, unknown>): unknown[] {
13	  const parts = ref.split('.');
14	  let val: unknown = allOutputs[parts[0]!];
15	  for (const part of parts.slice(1)) {
16	    if (val && typeof val === 'object') val = (val as Record<string, unknown>)[part];
17	    else { val = undefined; break; }
18	  }
19	  return Array.isArray(val) ? val : [];
20	}
21	
22	/**
23	 * Execution context for ONE `kind:'code'` tasklist node, built by the host
24	 * (CLI/pod) — never by core. `runCodeNode` loads + runs the node module's
25	 * `run(ctx, inputs)` in a Node worker with a `ctx` gated by the space/tasklist
26	 * `connections:` (db, callConnection, delegate). `inputs` is the SAME data an
27	 * agent fork of this node would receive: the seed-filtered tasklist input merged
28	 * with upstream task outputs (keyed by dependency id), plus `item`/`index` for a
29	 * forEach element. The returned object feeds `allOutputs`/`TaskEnvelope` exactly
30	 * like an agent node's output.
31	 */
32	export interface CodeNodeContext {
33	  runCodeNode(inputs: Record<string, unknown>): Promise<Record<string, unknown>>;
34	}
35	
36	/**
37	 * Maps a code node to its {@link CodeNodeContext}. Injected via
38	 * {@link RunTasklistOptions} by the CLI/pod (the headless tasklist runner, plan
39	 * step S9); the in-session yield-router threads one built from the session's
40	 * project scope when available. When ABSENT, encountering a code node fails that
41	 * task with a clear error (required-task-failure semantics) — core cannot
42	 * execute node modules itself. Called once per code node (before any forEach
43	 * fan-out), so the host can build per-node state up front.
44	 */
45	export type CodeNodeCtxFactory = (node: TaskNode) => CodeNodeContext;
46	
47	export interface RunTasklistOptions {
48	  name: string;
49	  space: Space;
50	  forkEngine: ForkEngine;
51	  seed?: Record<string, unknown>;
52	  tracer?: Tracer;
53	  parentScope?: TraceScope;
54	  /** Host-provided runner for `kind:'code'` nodes (see {@link CodeNodeCtxFactory}).
55	   *  Omit outside a CLI/pod context — code nodes then fail as required-task errors. */
56	  codeNodeCtxFactory?: CodeNodeCtxFactory;
57	}
58	
59	/**
60	 * Run a tasklist DAG and return a `TaskEnvelope` wrapping the goal task's output.
61	 *
62	 * Task→task UPSTREAM outputs stay RAW schema data (task files keep referencing
63	 * `plan.questions` etc.) — degradation metadata never leaks into upstream
64	 * variable values. Only the tasklist BOUNDARY result is enveloped:
65	 * `{ ok, degraded, data, reason?, degradedTasks? }`.
66	 */
67	export async function runTasklist(opts: RunTasklistOptions): Promise<TaskEnvelope> {
68	  const { name, space, forkEngine, seed, tracer, parentScope, codeNodeCtxFactory } = opts;
69	
70	  const tasklistDir = space.tasklists[name];
71	  if (!tasklistDir) {
72	    throw new Error(`Tasklist "${name}" not found in space`);
73	  }
74	
75	  // Validate the runtime seed against the tasklist's declared input schema
76	  // (tasklists/<name>/index.md frontmatter). No declared schema → accept any seed.
77	  const declaredInputKeys =
78	    tasklistDir.input && Object.keys(tasklistDir.input).length > 0
79	      ? Object.keys(tasklistDir.input)
80	      : undefined;
81	  if (declaredInputKeys) {
82	    const errors = validateInput(tasklistDir.input!, seed ?? {});
83	    if (errors.length > 0) {
84	      throw new Error(
85	        `Tasklist "${name}" received an invalid seed:\n  - ${errors.join('\n  - ')}`,
86	      );
87	    }
88	  }
89	
90	  // INPUT HARD FILTER: when the tasklist declares an `input` schema, forks receive
91	  // ONLY the declared keys — whatever extra baggage a delegator packed into the seed
92	  // (e.g. `parentHistory`, stray context) never rides into leaf prompts/ambient DTS.
93	  // This makes a leaf fork's prompt a pure function of (task file, declared inputs,
94	  // upstream outputs, forEach item) — identical shallow vs nested. No declared
95	  // schema → full passthrough (back-compat). Host-injected forEach `item`/`index`
96	  // are added AFTER the filter and are unaffected.
97	  const taskSeed = declaredInputKeys
98	    ? Object.fromEntries(Object.entries(seed ?? {}).filter(([k]) => declaredInputKeys.includes(k)))
99	    : seed;
100	
101	  const tasks = await loadTasklist(tasklistDir.slug, tasklistDir.files);
102	  validateDag(tasks);
103	  const goalTask = resolveGoalTask(tasks);
104	
