};
/** Time an Act's turn and record it as a metric (a perf target is a HANG DETECTOR, not an SLO). */
const timed = async (label, fn) => {
  const s = now();
  const r = await fn();
  report.metric(label, ((now() - s) / 1000).toFixed(0), ' s');
  return r;
};

